    def __init__(self, dim, num_experts=4, top_k=1, dropout_rate=0.0, bias=False):
        super().__init__()
        self.num_experts = num_experts
        self.top_k = top_k
        self.router = nn.Linear(dim, num_experts, bias=False)
        self.router.ROUTER_INIT = True
        self.experts = nn.ModuleList([
            SwiGLU(dim, dropout_rate=dropout_rate, bias=bias)
            for _ in range(num_experts)
        ])

    def forward(self, x):
        B, T, C = x.shape
        x_flat = x.view(-1, C)

        router_logits = self.router(x_flat)
        if self.training:
            # Add noise for exploration and load balancing
            router_logits = router_logits + torch.randn_like(router_logits) * 0.1

        routing_weights = F.softmax(router_logits, dim=-1)
        routing_weights, selected_experts = torch.topk(routing_weights, self.top_k, dim=-1)

        if self.top_k > 1:
            routing_weights = routing_weights / routing_weights.sum(dim=-1, keepdim=True)

        final_output = torch.zeros_like(x_flat)

        for i in range(self.num_experts):
            expert_mask = (selected_experts == i)
            token_indices, k_indices = torch.where(expert_mask)
            if token_indices.numel() > 0:
                expert_inputs = x_flat[token_indices]
                expert_outputs = self.experts[i](expert_inputs)
                expert_outputs = expert_outputs * routing_weights[token_indices, k_indices].unsqueeze(-1)
                final_output.index_add_(0, token_indices, expert_outputs)

        return final_output.view(B, T, C)


